import base64,os
FILES={
  'src/app/projects/[id]/page.tsx': '',
  'src/app/dashboard/page.tsx': '',
  'src/lib/thumbs.ts': '',
  'public/cad/pdf.min.mjs': '',
  'public/cad/pdf.worker.min.mjs': '',
}
for rel,b64 in FILES.items():
    d=os.path.dirname(rel)
    if d: os.makedirs(d,exist_ok=True)
    open(rel,'wb').write(base64.b64decode(b64)); print('ecrit',rel)
print('=== Refonte UX + apercus PDF/DWG appliquee. git add -A && git commit && git push ===')